package be.schaubroeck.lpb.rkm.rekenmotor.main;

import be.schaubroeck.lpb.rkm.corehr.config.RekenmotorCoreHrClient;
import be.schaubroeck.lpb.rkm.rekenmotor.CoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategy;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategyFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService.OpdrachtData;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenmotorService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RkmCoreHrConfiguratieMapper;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ToegepasteTussenkomstFixer;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.corehr.extern.uitgaand.rekenmotor.rekenmotor.RekenmotorConfiguratieDTO;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.AdminService;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.temporal.clock.TheClock;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import com.google.common.collect.Multimap;
import com.google.common.collect.Ordering;
import com.google.common.collect.SetMultimap;
import com.google.common.collect.TreeMultimap;
import lombok.Setter;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.support.ClassPathXmlApplicationContext;

import java.util.Calendar;
import java.util.Collection;
import java.util.List;
import java.util.Set;
import java.util.TreeSet;

@Slf4j
public class StandAloneNeutralisatie {

    public static void start(
            Integer adminid, LocalDate beginDatum, LocalDate eindDatum, LocalDate rekenDatum, String serverBundle,
            boolean throwExceptions) {
        log.info("Starten neutralisatie voor adminid {} van {} tot {}", adminid, beginDatum, eindDatum);
        ClassPathXmlApplicationContext context = new ClassPathXmlApplicationContext(serverBundle);
        StandAloneNeutralisatie standAloneNeutralisatie = (StandAloneNeutralisatie) context.getBean("standAloneNeutralisatie");

        MainHelper.shutdownSchedulers(context);

        standAloneNeutralisatie.setThrowExceptions(throwExceptions);
        standAloneNeutralisatie.startTimeLogging();
        standAloneNeutralisatie.doeBerekeningen(adminid, beginDatum, eindDatum, rekenDatum);
        standAloneNeutralisatie.endTimeLogging();
        context.close();

    }

    private long timeMillis;

    public void startTimeLogging() {
        timeMillis -= Calendar.getInstance().getTimeInMillis();
    }

    public void endTimeLogging() {
        timeMillis += Calendar.getInstance().getTimeInMillis();
        log.info("Duur: {} seconden", timeMillis / 1000.0);
    }

    @Autowired
    private AdminService wdcAdminService;
    @Autowired
    private RekenmotorService rekenmotorService;

    @Autowired
    private RekenMotorStrategyFactory rekenMotorStrategyFactory;

    @Autowired
    private ExtraSqlService extraSqlService;

    @Autowired
    private ToegepasteTussenkomstFixer toegepasteTussenkomstFixer;

    @Autowired
    private ConstantService constantService;

    @Setter
    @Autowired
    private RekenmotorCoreHrClient rekenmotorCoreHrClient;
    @Autowired
    private RkmCoreHrConfiguratieMapper rkmCoreHrConfiguratieMapper;

    @Setter
    private boolean throwExceptions = false;

    public void doeBerekeningen(Integer adminid, LocalDate beginDatum, LocalDate eindDatum, LocalDate rekenDatum) {
        try {
            Admin admin = wdcAdminService.getById(adminid);
            if (admin == null) {
                throw new RuntimeException("Admin werd niet gevonden");
            }
            doeBerekeningen(admin, beginDatum, eindDatum, rekenDatum);
        } catch (RuntimeException e) {
            handleException(e);
        }
    }

    public void doeBerekeningen(Admin admin, LocalDate beginDatum, LocalDate eindDatum) {
        doeBerekeningen(admin, beginDatum, eindDatum, null);
    }

    public void doeBerekeningen(Admin admin, LocalDate beginDatum, LocalDate eindDatum, LocalDate rekenDatum) {
        CacheContext.getInstance().clearCachedServices(Scope.ALL);
        log.trace("StandAloneNeutralisatie.doeBerekeningen({}, {}, {})", admin.getAdminDir().trim(), beginDatum, eindDatum);
        TimeTools timeTools = new TimeTools(admin, constantService);
        RekenMotorStrategy strategy = rekenMotorStrategyFactory.getNeutralisatieStrategy(admin);
        if (rekenDatum == null) {
            rekenDatum = TheClock.getInstance().getToday();
        }
        LocalDate boekDatum = rekenDatum;
        LocalDate beslagDatum = rekenDatum;
        LocalDateTime rekenTijdstip = TheClock.getInstance().getNow();
        beginDatum = beginDatum.dayOfMonth().withMinimumValue();
        eindDatum = eindDatum.dayOfMonth().withMaximumValue();

        Multimap<LocalDate, OpdrachtData> datumToOpdrachtDatas =
                extraSqlService.findOpdrachtenGebruiktInRekenResultaten(admin, beginDatum, eindDatum, rekenTijdstip);

        long aantalBehandeldeItems = 0;

        List<RekenmotorConfiguratieDTO> rekenmotorConfiguratieDTOS = rekenmotorCoreHrClient.getConfig(admin.getId());
        List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties = rkmCoreHrConfiguratieMapper.map(rekenmotorConfiguratieDTOS);
        CoreHrConfiguratie coreHrConfiguratie = CoreHrConfiguratie.builder().rkmCoreHrConfiguraties(rkmCoreHrConfiguraties).build();
        LocalDate loopDatum = beginDatum;
        while (loopDatum.compareTo(eindDatum) <= 0) {
            LocalDateInterval rekenPeriode = new Month(loopDatum);
            Collection<OpdrachtData> opdrachten = datumToOpdrachtDatas.get(rekenPeriode.getStart());
            SetMultimap<Integer, Integer> persoonIdTopdrachtNrs = TreeMultimap.create(Ordering.natural(), Ordering.natural());
            SetMultimap<Integer, Integer> persoonIdTopdrachtNrsVoorschot = TreeMultimap.create(Ordering.natural(), Ordering.natural());
            for (OpdrachtData opdracht : opdrachten) {
                if (rekenPeriode.getEnd().compareTo(opdracht.getBeginDatum()) >= 0 && rekenPeriode.getStart().compareTo(opdracht.getEindDatum()) <= 0) {
                    if (opdracht.getRekenmodus() == Rekenmodus.VOORSCHOT) {
                        persoonIdTopdrachtNrsVoorschot.put(opdracht.getPersoonId(), opdracht.getOpdrachtnr());
                    } else {
                        persoonIdTopdrachtNrs.put(opdracht.getPersoonId(), opdracht.getOpdrachtnr());
                    }
                }
            }
            for (Integer persoonId : persoonIdTopdrachtNrs.keySet()) {
                Set<Integer> opdrachtNrs = persoonIdTopdrachtNrs.get(persoonId);
                for (Integer opdrachtNr : opdrachtNrs) {
                    persoonIdTopdrachtNrsVoorschot.remove(persoonId, opdrachtNr);
                }
            }
            Set<Integer> persoonIds = new TreeSet<>(persoonIdTopdrachtNrs.keySet());
            persoonIds.addAll(persoonIdTopdrachtNrsVoorschot.keySet());

            RekenTijd rekenTijd = new RekenTijd(rekenPeriode, rekenDatum, boekDatum, beslagDatum, rekenTijdstip);
            boolean isApo = isApo(admin, rekenTijd);
            for (Integer persoonId : persoonIdTopdrachtNrs.keySet()) {
                log.info("Aantal behandelde items: {} ", ++aantalBehandeldeItems);

                Set<Integer> opdrachtNrs = persoonIdTopdrachtNrs.get(persoonId);
                Set<Integer> opdrachtNrsVoorschot = persoonIdTopdrachtNrsVoorschot.get(persoonId);

                log.trace("PersoonId: {}, OpdrachtNrs: {}, BeginDatum: {}", persoonId, opdrachtNrs, rekenPeriode.getStart());

                try {
                    String actor = "neutralisatie";
                    rekenmotorService.berekenLoon(admin, persoonId, opdrachtNrs, rekenTijd, strategy, Rekenmodus.NORMAAL, actor, coreHrConfiguratie);
                    if (!isApo) {
                        rekenmotorService.berekenLoon(admin, persoonId, opdrachtNrsVoorschot, rekenTijd, strategy, Rekenmodus.VOORSCHOT, actor, coreHrConfiguratie);
                    }

                    Integer fiscaalJaar = timeTools.bepaalFiscaalJaar(beginDatum, rekenDatum, isApo);
                    toegepasteTussenkomstFixer.fixToegepasteTussenkomsten(admin, persoonId, rekenTijd.beginDatum, fiscaalJaar);
                } catch (Exception e) {
                    handleException(new RuntimeException(
                            "Fout bij neutralisatie van persoonId: " + persoonId + ", opdrachtNrs: " + opdrachtNrs + ", beginDatum: " + rekenPeriode
                                    .getStart(), e));
                }

            }
            loopDatum = loopDatum.plusMonths(1);
        }
    }

    private boolean isApo(Admin admin, RekenTijd rekenTijd) {
        LocalDate datumAansluiting = constantService.getByCodeDatum(admin, Konstanten.KST_STARTDATUM_SWEEP, rekenTijd.beginDatum).getDatum();
        return datumAansluiting.compareTo(rekenTijd.beginDatum) > 0;
    }

    private static final String FATAL_MESSAGE = "Er werd een Exception gegooid bij de neutralisatie";

    private void handleException(Exception exception) {
        if (throwExceptions) {
            throw new MessageException(FATAL_MESSAGE, exception);
        } else {
            log.debug(FATAL_MESSAGE, exception);
        }
    }

}
